            { type = "list_item", text = "Arcane", level = 1 },
            { type = "dev_note", text = "Arcane is behind the other Mage specializations, so we’re increasing the damage of some of their core spells. These are the more difficult spells to fully channel, so we’d like them to feel more rewarding when you do cast them.", level = 2 },
            { type = "list_item", text = "Arcane Blast damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Arcane Missile damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "Fire, particularly Sunfury, is able to deal significant burst during their Combustion windows. We’d like to reduce that with that caveat that casting Fireball should still feel rewarding.", level = 2 },
            { type = "list_item", text = "Pyroblast damage reduced by 6% in PvP combat.", level = 2 },
            { type = "list_item", text = "Fireball damage increased by 80% in PvP combat.", level = 2 },
            { type = "list_item", text = "Sunfury: Codex of the Sunstriders now increases spell damage during Combustion by 1% for each Spellfire Sphere consumed in PvP combat (was 2%).", level = 2 },
