            { type = "list_item", text = "Midnight Crystal health reduced by 5% on Mythic difficulty.", level = 2 },
            { type = "dev_note", text = "The following adjustments are aimed at reducing difficulty for smaller groups, with the greatest reductions applying to 10-player groups. These affect Raid Finder, Normal, and Heroic difficulties.", level = 2 },
