        ["2026-05-12-time-is-running-out-play-midnight-for-a-classic-anniversary-edition-fl-c43e9a3a1b"] = {
            id = "2026-05-12-time-is-running-out-play-midnight-for-a-classic-anniversary-edition-fl-c43e9a3a1b",
            post_key = "c43e9a3a1b",
            title = "Time is Running Out! Play Midnight for a Classic Anniversary Edition Flying Mount",
            category = "Blogs (US)",
            timestamp = 1778605642,
            url = "https://news.blizzard.com/en-us/article/24267942/play-midnight-for-a-classic-anniversary-edition-flying-mount",
            content = {
            { type = "p", text = "Earn the menacing Voidfeather Dragonhawk flying mount to carry you through the fel-scarred realm of Outland in Burning Crusade Classic Anniversary Edition* after completing the introduction scenario in World of Warcraft: Midnight**." },
            { type = "p", text = "When: March 17 through May 17" },
            { type = "hr" },
            { type = "h3", text = "Defend the Sunwell" },
            { type = "p", text = "Quel'Thalas is under siege! Complete the intro scenario of Midnight, pitting you against Void forces during their invasion of the home of the Blood Elves, and earn the \"Echoes of Midnight\" achievement before the promotion period ends to get the Voidfeather Dragonhawk flying mount for use in your Burning Crusade Classic Anniversary adventures." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-12-time-is-running-out-play-midnight-for-a-classic-anniversary-edition-fl-c43e9a3a1b\\image-1.jpg" },
            { type = "p", text = "The Voidfeather Dragonhawk mount is only available in World of Warcraft: The Burning Crusade Classic Anniversary realms, and characters must have Expert Riding or better to use it. This mount automatically scales to the fastest riding skill known by each character." },
            { type = "hr" },
            { type = "h3", text = "How to Start the Midnight Intro Scenario" },
            { type = "p", text = "Adventure is calling you home in Midnight!" },
            { type = "p", text = "Buy Now" },
            { type = "hr" },
            { type = "p", text = "*Requires a World of Warcraft® Subscription or Game Time. **Requires access to World of Warcraft®: Midnight (sold separately)." },
            { type = "p", text = "Available until May 18, 2026, 10:00 am PDT (18:00 BST)." },
            },
        },
        ["2026-05-11-additional-guardian-tuning-13-may-3859805c86"] = {
            id = "2026-05-11-additional-guardian-tuning-13-may-3859805c86",
            post_key = "3859805c86",
            title = "Additional Guardian Tuning - 13 May",
            category = "Druid (EU)",
            timestamp = 1778543493,
            url = "https://eu.forums.blizzard.com/en/wow/t/619090/1",
            content = {
            { type = "p", text = "Our recent adjustments to Guardian have made the Elune’s Chosen build stronger than intended. We’re going to take steps to bring this back in line with realm restarts during scheduled weekly maintenance this week." },
            { type = "h2", text = "CLASSES" },
            { type = "h3", text = "Druid" },
            { type = "list_item", text = "Guardian", level = 0 },
            { type = "list_item", text = "Thrash direct damage reduced by 25%.", level = 1 },
            { type = "list_item", text = "Elune’s Favored now heals for 15% of Arcane damage dealt (was 25%).", level = 1 },
            { type = "dev_note", text = "These changes aim to bring this build closer to its expected output: high-damage relative to other tanks, but not abnormally so.", level = 0 },
            { type = "p", text = "We recognize that the build in question avoids the Apex talent. With this tuning, we’re choosing to not break the Elune’s Chosen build or require the Apex talent. We have further plans to update the Guardian Apex Talent in a future patch to give us more flexibility with it and alleviate some of the current pain points for Druids." },
            },
        },
        ["2026-05-11-additional-guardian-tuning-may-12-99a2246534"] = {
            id = "2026-05-11-additional-guardian-tuning-may-12-99a2246534",
            post_key = "99a2246534",
            title = "Additional Guardian Tuning - May 12",
            category = "Druid (US)",
            timestamp = 1778543487,
            url = "https://us.forums.blizzard.com/en/wow/t/2305161/1",
            content = {
            { type = "p", text = "Our recent adjustments to Guardian have made the Elune’s Chosen build stronger than intended. We’re going to take steps to bring this back in line with realm restarts during scheduled weekly maintenance this week." },
            { type = "h2", text = "CLASSES" },
            { type = "h3", text = "Druid" },
            { type = "list_item", text = "Guardian", level = 0 },
            { type = "list_item", text = "Thrash direct damage reduced by 25%.", level = 1 },
            { type = "list_item", text = "Elune’s Favored now heals for 15% of Arcane damage dealt (was 25%).", level = 1 },
            { type = "dev_note", text = "These changes aim to bring this build closer to its expected output: high-damage relative to other tanks, but not abnormally so.", level = 0 },
            { type = "p", text = "We recognize that the build in question avoids the Apex talent. With this tuning, we’re choosing to not break the Elune’s Chosen build or require the Apex talent. We have further plans to update the Guardian Apex Talent in a future patch to give us more flexibility with it and alleviate some of the current pain points for Druids." },
            },
        },
        ["2026-05-08-tank-adjustments-incoming-may-12-ae0b4dd232"] = {
            id = "2026-05-08-tank-adjustments-incoming-may-12-ae0b4dd232",
            post_key = "ae0b4dd232",
            title = "Tank Adjustments Incoming – May 12",
            category = "General Discussion (US)",
            timestamp = 1778261012,
            url = "https://us.forums.blizzard.com/en/wow/t/2303865/1",
            content = {
            { type = "p", text = "We’re deploying some tuning for tanks with scheduled weekly maintenance, as we feel that tanking has fallen behind our intentions for keeping up with the incoming damage in Mythic+. We’re focusing on two goals." },
            { type = "p", text = "We’re hopeful that these changes will help bridge the gap between tank specs, and we will continue to monitor and tune as necessary." },
            { type = "h2", text = "CLASSES" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Blood", level = 1 },
            { type = "dev_note", text = "We are looking at smoothing out the damage intake of Blood outside of their cooldown window by increasing the consistency and uptime of their Apex Talent. To further help these windows of high damage intake we are also increasing their Health and Death Strike healing.", level = 1 },
            { type = "list_item", text = "Dancing Rune Weapon grants 25% Parry (was 20%).", level = 2 },
            { type = "list_item", text = "Blood Fortification grants 40% Stamina (was 35%).", level = 2 },
            { type = "list_item", text = "Improved Death Strike healing increased to 15% (was 5%).", level = 2 },
            { type = "list_item", text = "Dance of Midnight grants Dancing Rune Weapon for 8 seconds (was 6 seconds).", level = 2 },
            { type = "list_item", text = "Dance of Midnight chance to proc increased to 12.5% (was 10%).", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "dev_note", text = "Vengeance Demon Hunter’s baseline defenses are its most lacking, while cooldown availability and values are currently serving the spec well. As a result, we will be primarily targeting core values for Health and damage reduction, with an additional smaller increase specifically to Armor.", level = 1 },
            { type = "list_item", text = "Demonic Wards now reduces all damage taken by 12% (was 8%).", level = 2 },
            { type = "list_item", text = "Thick Skin now grants 55% increased Stamina (was 50%).", level = 2 },
            { type = "list_item", text = "Effectiveness of Mastery: Fel Blood increased by 20%.", level = 2 },
            { type = "list_item", text = "Void Reaver now causes Frailty to reduce damage taken by 5% (was 4%).", level = 2 },
            { type = "list_item", text = "Demonic Wards now reduces all damage taken by 12% (was 8%).", level = 2 },
            { type = "list_item", text = "Thick Skin grants 55% Stamina (was 50%).", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "With these changes, we’re aiming to improve baseline durability for Protection Paladins by increasing passive effects which contribute to effective health. We’re also addressing on-demand survivability with adjustments to defensive cooldown coverage and strength.", level = 1 },
            { type = "list_item", text = "Blessing of Dusk reduces damage taken by up to 20%, increasing as your health decreases (was 10%).", level = 2 },
            { type = "list_item", text = "Sanctified Plates increases stamina by 7/15% (was 5/10%).", level = 2 },
            { type = "list_item", text = "Ardent Defender duration increased to 12 seconds (was 8 seconds).", level = 2 },
            { type = "list_item", text = "Ardent Defender now reduces damage taken by 30% (was 20%).", level = 2 },
            { type = "list_item", text = "Sentinel duration increased to 20 seconds (was 16 seconds).", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "Protection melee damage mitigation is quite strong, but is a bit behind for magical attacks and damage-over-time effects. These changes are aimed at strengthening those areas as well as making it easier to maintain healthy Ignore Pain values.", level = 1 },
            { type = "list_item", text = "Fight Through Flames reduces magic damage taken by 6% (was 4%).", level = 2 },
            { type = "list_item", text = "Phalanx reduces damage enemies deal to you by 8% (was 5%).", level = 2 },
            { type = "list_item", text = "Ignore Pain effectiveness increased by 8%.", level = 2 },
            },
        },
        ["2026-05-08-tank-adjustments-incoming-13-may-d96c3687a1"] = {
            id = "2026-05-08-tank-adjustments-incoming-13-may-d96c3687a1",
            post_key = "d96c3687a1",
            title = "Tank Adjustments Incoming – 13 May",
            category = "General Discussion (EU)",
            timestamp = 1778261007,
            url = "https://eu.forums.blizzard.com/en/wow/t/618825/1",
            content = {
            { type = "p", text = "We’re deploying some tuning for tanks with scheduled weekly maintenance, as we feel that tanking has fallen behind our intentions for keeping up with the incoming damage in Mythic+. We’re focusing on two goals." },
            { type = "p", text = "We’re hopeful that these changes will help bridge the gap between tank specs, and we will continue to monitor and tune as necessary." },
            { type = "h2", text = "CLASSES" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Blood", level = 1 },
            { type = "dev_note", text = "We are looking at smoothing out the damage intake of Blood outside of their cooldown window by increasing the consistency and uptime of their Apex Talent. To further help these windows of high damage intake we are also increasing their Health and Death Strike healing.", level = 1 },
            { type = "list_item", text = "Dancing Rune Weapon grants 25% Parry (was 20%).", level = 2 },
            { type = "list_item", text = "Blood Fortification grants 40% Stamina (was 35%).", level = 2 },
            { type = "list_item", text = "Improved Death Strike healing increased to 15% (was 5%).", level = 2 },
            { type = "list_item", text = "Dance of Midnight grants Dancing Rune Weapon for 8 seconds (was 6 seconds).", level = 2 },
            { type = "list_item", text = "Dance of Midnight chance to proc increased to 12.5% (was 10%).", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "dev_note", text = "Vengeance Demon Hunter’s baseline defenses are its most lacking, while cooldown availability and values are currently serving the spec well. As a result, we will be primarily targeting core values for Health and damage reduction, with an additional smaller increase specifically to Armor.", level = 1 },
            { type = "list_item", text = "Demonic Wards now reduces all damage taken by 12% (was 8%).", level = 2 },
            { type = "list_item", text = "Thick Skin now grants 55% increased Stamina (was 50%).", level = 2 },
            { type = "list_item", text = "Effectiveness of Mastery: Fel Blood increased by 20%.", level = 2 },
            { type = "list_item", text = "Void Reaver now causes Frailty to reduce damage taken by 5% (was 4%).", level = 2 },
            { type = "list_item", text = "Demonic Wards now reduces all damage taken by 12% (was 8%).", level = 2 },
            { type = "list_item", text = "Thick Skin grants 55% Stamina (was 50%).", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "With these changes, we’re aiming to improve baseline durability for Protection Paladins by increasing passive effects which contribute to effective health. We’re also addressing on-demand survivability with adjustments to defensive cooldown coverage and strength.", level = 1 },
            { type = "list_item", text = "Blessing of Dusk reduces damage taken by up to 20%, increasing as your health decreases (was 10%).", level = 2 },
            { type = "list_item", text = "Sanctified Plates increases stamina by 7/15% (was 5/10%).", level = 2 },
            { type = "list_item", text = "Ardent Defender duration increased to 12 seconds (was 8 seconds).", level = 2 },
            { type = "list_item", text = "Ardent Defender now reduces damage taken by 30% (was 20%).", level = 2 },
            { type = "list_item", text = "Sentinel duration increased to 20 seconds (was 16 seconds).", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "Protection melee damage mitigation is quite strong, but is a bit behind for magical attacks and damage-over-time effects. These changes are aimed at strengthening those areas as well as making it easier to maintain healthy Ignore Pain values.", level = 1 },
            { type = "list_item", text = "Fight Through Flames reduces magic damage taken by 6% (was 4%).", level = 2 },
            { type = "list_item", text = "Phalanx reduces damage enemies deal to you by 8% (was 5%).", level = 2 },
            { type = "list_item", text = "Ignore Pain effectiveness increased by 8%.", level = 2 },
            },
        },
