            { type = "list_item", text = "Fixed a bug that prevented the expected audio from playing when a Rogue enters stealth.", level = 1 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "Fixed a bug that could prevent Decor Duel participants from receiving base Illusionary Coin rewards by incorrectly evaluating them to be AFK.", level = 0 },
            { type = "list_item", text = "Humanoid tracking abilities no longer reveal players in Decor Duel.", level = 0 },
            { type = "list_item", text = "Achievements earned in Decor Duel are now account-wide, as intended.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Addressed an issue where Lindormi's Guidance could be applied to players outside of Mythic+ dungeons.", level = 0 },
            { type = "list_item", text = "March on Quel’Danas", level = 0 },
            { type = "list_item", text = "Midnight Falls", level = 1 },
            { type = "list_item", text = "Resolved issues with Torchbearer failing to prevent players from receiving applications of Midnight or failing to remove applications of Midnight.", level = 2 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Addressed an issue preventing sockets from being added to Champion items obtained from Midnight Renown vendors.", level = 0 },
            { type = "list_item", text = "Fixed an issue where acquiring a Nebulous Voidcore with Thalassian Tokens of Merit would cause Decimus to only grant one of his two weekly Nebulous Voidcores upon quest turn-in.", level = 0 },
            { type = "dev_note", text = "Players who have two Nebulous Voidcores in their currency window while showing \"Season Maximum: 1/2\" can now safely complete any of Decimus's quests again to receive their missing Nebulous Voidcore.", level = 1 },
            { type = "h3", text = "Professions" },
            { type = "list_item", text = "Adjusted the cost of Thalassian Competitor's Chain Tunic to 5 Heraldry (was 4) to be in line with other crafted PvP chestpieces.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "The Ancient Visionstone can once again be interacted with for the Harandar repeatable legends quests \"The Story of the Echoless Flame\" and \"The Story of Russula's Outreach\".", level = 0 },
            { type = "list_item", text = "Fixed a bug where the daily quest \"Ephemeral Masquerade\" appeared to be a low-level quest, rather than the intended blue exclamation point.", level = 0 },
            },
        },
        ["2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359"] = {
            id = "2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359",
            post_key = "6c177ee359",
            title = "WoW Weekly: Classic Anniversary Edition, May's Trading Post, Children's Week, and More!",
            category = "Blogs (EU)",
            timestamp = 1777655174,
            url = "https://news.blizzard.com/en-gb/article/24276752/wow-weekly-classic-anniversary-edition-may-s-trading-post-children-s-week-and-more",
            content = {
            { type = "p", text = "Each week meets you with adventurous discovery and fresh rewards—be sure to check in to learn more about what awaits you in Azeroth." },
            { type = "hr" },
            { type = "h2", text = "BCC ANNIVERSARY EDITION: OVERLORDS OF OUTLAND ARRIVES 14 MAY" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-1.jpg" },
            { type = "p", text = "The battle for Outland heats up! Take the fight to Illidan Stormrage's lieutenants, brave two new raids, compete in Arena Season 2, and pursue new rewards across the shattered world of Outland." },
            { type = "h3", text = "Global Launch Date/Time: 14 May at 23:00 BST" },
            { type = "list_item", text = "New raids", level = 0 },
            { type = "list_item", text = "Tempest Keep: The Eye (Kael'thas Sunstrider) and Serpentshrine Cavern (Lady Vashj)", level = 1 },
            { type = "list_item", text = "Arena Season 2", level = 0 },
            { type = "list_item", text = "New rewards and updated progression.", level = 1 },
            { type = "list_item", text = "Swift Flight Form", level = 0 },
            { type = "list_item", text = "Druid questline (including the Idol of the Raven Goddess) culminating in a showdown with Anzu the Raven God in Heroic Sethekk Halls", level = 1 },
            { type = "list_item", text = "New daily factions", level = 0 },
            { type = "list_item", text = "Earn rewards with Ogri'la and the Sha'tari Skyguard", level = 1 },
            { type = "list_item", text = "New profession recipes", level = 0 },
            { type = "list_item", text = "Engineering epic goggles and new Alchemy discoveries (including raid-friendly cauldrons)", level = 1 },
            { type = "p", text = "Get ready to adventure across the shattered skies and torn lands of Outland as you continue to protect Azeroth from the threat of destruction, beginning 14 May. For more details, read through our previously published overview." },
            { type = "hr" },
            { type = "h2", text = "GET DECKED OUT WITH GILNEAN FLAIR AT MAY’S TRADING POST" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-2.jpg" },
            { type = "p", text = "Ensemble: Pyrewood Rebel StreetwearHead, Chest x2, Waist, Wrist, Legs x2, and Feet“Dashing, Dapper, and Dastardly: This fashionable ensemble has it all.”" },
            { type = "p", text = "The Gray Skies of Gilneas won’t put a damper on your style when you visit the May Trading Post. Take part in a variety of activities to earn this month’s reward— get the Ensemble: Pyrewood Rebel Streetware transmog set." },
            { type = "p", text = "Visit T&W (Tawney and Wilder) just outside the Mage District in Stormwind or the Zen’shiri Trading Post next to Grommash Hold in Orgrimmar to check out all the latest items they have available." },
            { type = "p", text = "Players can also visit the Trading Post in the capital city of Dornogal (The Foregrounds) on the Isle of Dorn, where representatives of both Tawney and Wilder and the Zen’shiri Trading Post are open for business." },
            { type = "p", text = "Check Out What's in Stock for May" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-3.jpg" },
            { type = "p", text = "Gilneas Loyalist’s Rouncey Mount“Steadfast and proud, this steed carries its rider with quiet dignity and unyielding resolve.”" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-4.jpg" },
            { type = "p", text = "Pyrewood Rebel’s RounceyMount“After diligent training from riders in both worgen and human forms, these horses will now bear any rider in Gilnean finery.”" },
            { type = "image", width = 366, height = 420, u = 0.714844, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-5.jpg" },
            { type = "p", text = "Scarred Tabard of GilneasTabard“Wear your curse with pride.”" },
            { type = "image", width = 366, height = 420, u = 0.714844, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-6.jpg" },
            { type = "p", text = "Ensemble: Attire of the Gilneas FoxHead, Shoulder, Chest/Robe, Waist, Legs, Feet, Hands, Cloak“For unknown reasons, when donning this ensemble, everyone will take great interest in the things you say.”" },
            { type = "image", width = 366, height = 420, u = 0.714844, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-7.jpg" },
            { type = "p", text = "Stylish Brown Top HatHead“Carry the weight of tradition with poise.”" },
            { type = "p", text = "Read through our article for a detailed list of all the items available from the May Trading Post and how to get them." },
            { type = "p", text = "Champions new or returning to World of Warcraft and The War Within who want to know more can take a tour of the Trading Post to learn everything you need to know, from where to find it to how you can earn additional Trader's Tender through the Traveler's Log." },
            { type = "hr" },
            { type = "h2", text = "LAST CHANCE FOR CHILDREN'S WEEK" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-8.jpg" },
            { type = "p", text = "Be the champion when you give back to the children of Azeroth during Children's Week—take an orphan under your wing and show them what the hero's life is like!" },
            { type = "p", text = "When: 27 April–4 May" },
            { type = "p", text = "What's New in Midnight" },
            { type = "list_item", text = "Children's Week comes to Midnight's reimagined Silvermoon City in Quel'Thalas!", level = 0 },
            { type = "list_item", text = "New Toy: Nap Mat", level = 0 },
            { type = "list_item", text = "A new Children's Week vendor is standing near the Holiday Enthusiast, between the Auction House and the Trading Post, in the reimagined Silvermoon City of Midnight .", level = 0 },
            { type = "p", text = "Visit Orphan Matron Nightingale in Stormwind, Orphan Matron Battlewail in Orgrimmar, Orphan Matron Mercy in Shattrath, Orphan Matron Aria in Dalaran, Caretake Padae in Dazar'alor, or Orphan Matron Westerson in Boralus, or Matron in Training Ullna in Khaz Algar, and make a child's dream come true!" },
            { type = "h3", text = "WoW Classic" },
            { type = "p", text = "The WoW Classic version of Children's Week is also available for the giving souls of the Horde and the Alliance to help make orphan dreams come true." },
            { type = "h3", text = "When: 27 April–4 May" },
            { type = "p", text = "Players level 10 and above can visit Orphan Matron Nightingale in Stormwind (Alliacne), Orphan Matron Battlewail in Orgrimmar (Horde), Orphan Matron Mercy in Shattrath (Neutral), or Orphan Matron Aria in Dalaran (Neutral) and make a child's dream come true." },
            { type = "p", text = "Upon completing the requested tasks from a chosen orphan, WoW Classic progression players have their choice of a cute, non-combat pet! These pets are account-wide, so feel free to share them with your alts." },
            { type = "hr" },
            { type = "h2", text = "STORE UPDATES" },
            { type = "h3", text = "Transform Your Home With the Cozy Treehouse Retreat Bundle and More!" },
            { type = "p", text = "Bring your spring sanctuary to life, inside and out. Make your home among the branches of two new home exteriors and a variety of delightful Spring-themed Housing decor items. If there's something you fancy, you can also purchase decor items in these packs individually from the in-game shop or the Battle.net shop." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-9.jpg" },
            { type = "p", text = "Cozy Treehouse Retreat Bundle" },
            { type = "p", text = "Transform your home’s exterior with blooming blossoms or lush garden charm. Settle into a peaceful canopy retreat that feels like home." },
            { type = "h3", text = "Buy Now" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-10.jpg" },
            { type = "p", text = "Lush Garden Decor Pack 2" },
            { type = "p", text = "Fill your home with a cozy, inviting feeling through leafy accents and earthy details. Each piece helps create a vibrant garden inspired space." },
            { type = "h3", text = "Buy Now" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-11.jpg" },
            { type = "p", text = "Spring Blossom Decor Pack 2" },
            { type = "p", text = "Add a soft touch to any home with blossoming decor pieces, helping you create a lovely, serene space bringing Spring indoors." },
            { type = "h3", text = "Buy Now" },
            { type = "h3", text = "Azeroth Blossoms Anew: Choose Your Blooming Arboon Mount" },
            { type = "p", text = "Climb atop a Blooming Arboon Mount adorned in vibrant fuchsia or warm amber hues to carry you and the strength of the forest wherever they roam." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-12.jpg" },
            { type = "p", text = "Blossomback Arboon" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-05-01-wow-weekly-classic-anniversary-edition-mayx27s-trading-post-childrenx2-6c177ee359\\image-13.jpg" },
            { type = "p", text = "Amberback Arboon" },
            { type = "hr" },
            { type = "h2", text = "BUILDING AZEROTH: UPDATING QUEL'THALAS" },
            { type = "p", text = "Flip through charcoal drawings of Eversong Woods, walk through an in-progress Shepherd's Gate, see the instrument that brought the dooming sound of the Voidstorm, and more." },
            { type = "p", text = "On this Building Azeroth, let the World of Warcraft dev team give you a behind-the-scenes look at how they completely rebuilt the elven kingdom of Quel'Thalas and its capital city, Silvermoon." },
            { type = "p", text = "Adventure is calling you home! Experience the next chapter in the Worldsoul Saga as things become more dire for the world of Azeroth in World of Warcraft®: Midnight™." },
            { type = "hr" },
            { type = "p", text = "Follow along as you get ready for new challenges and can’t-miss moments in-game. Whenever news drops, find it on the World of Warcraft news site, along with announcements, highlights, and what to tackle next." },
            },
        },
