        ["2026-04-30-hotfixes-april-29-2026-4e1e598eb8"] = {
            id = "2026-04-30-hotfixes-april-29-2026-4e1e598eb8",
            post_key = "4e1e598eb8",
            title = "Hotfixes: April 29, 2026",
            category = "Blogs (US)",
            timestamp = 1777513128,
            url = "https://news.blizzard.com/en-us/article/24276957/hotfixes-april-28-2026",
            content = {
            { type = "p", text = "Here you'll find a list of hotfixes that address various issues related to World of Warcraft: Midnight, Mists of Pandaria Classic, Season of Discovery, Burning Crusade Classic, WoW Classic Era, and Hardcore. Some of the hotfixes below take effect the moment they were implemented, while others may require scheduled realm restarts to go into effect. Please keep in mind that some issues cannot be addressed without a client-side patch update. This list will be updated as additional hotfixes are applied." },
            { type = "h2", text = "HOTFIXES" },
            { type = "hr" },
            { type = "h3", text = "April 29, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Flameshaper: Twin Flame will no longer bounce to enemy targets that the Evoker is not in combat with.", level = 1 },
            { type = "list_item", text = "Fixed an issue where Titan's Gift and Titanic Wrath were not increasing the damage of the final few ticks of Disintegrate for Preservation and Devastation Evokers.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "All damage dealt increased by approximately 12%.", level = 2 },
            { type = "dev_note", text = "Restoration shamans were intended to gain a 30% damage increase with the release of patch 12.0.5, but an error resulted in them gaining about half of that amount. This 12% increase brings them up to a total of +30% damage when compared to before patch 12.0.5.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Fatal Echoes would consume a Soul Shard when activated.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Unstable Affliction would consume all stacks of Shard Instability.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "Slams from Fervor of Battle which critically strike will now correctly trigger Mortal Wounds.", level = 2 },
            { type = "list_item", text = "Deep Wounds applied by Execute no longer deal double the intended damage.", level = 2 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "The Enchanted Hourglass now has a progress bar, and its timer is now better aligned with the toy's duration.", level = 0 },
            { type = "h3", text = "Housing" },
            { type = "list_item", text = "Fixed a bug where the neighborhood weekly quest “Lost Animals” could become unavailable to players who completed it previously.", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Cosmic Hunter's Glaive and Fangs of the Invader should now have Intellect for Devourer Demon Hunters.", level = 0 },
            { type = "h3", text = "Professions" },
            { type = "list_item", text = "Cooking", level = 0 },
            { type = "list_item", text = "Fixed an issue with Hearty Well Fed being refreshed by standard Well Fed foods.", level = 1 },
            { type = "h3", text = "Reputation" },
            { type = "list_item", text = "Midnight World Quests now correctly award increased reputation while Sign of the Emissary is active.", level = 0 },
            { type = "h3", text = "Void Assaults" },
            { type = "list_item", text = "Imperator Pertinax should no longer die easily during the Eversong Void Incursion.", level = 0 },
            { type = "list_item", text = "Fixed a bug that could prevent some players who were properly in combat with the Void-Corrupted creature from receiving credit toward the Cosmic Slayer achievement.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "April 28, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Fixed an issue where Blooming Infusion was counting each target of Nature's Bounty or Rampant Growth as an additional cast.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
