            url = "https://eu.forums.blizzard.com/en/wow/t/617226/1",
            content = {
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-04-24-wow-weekly-midnight-1205-content-update-twitch-drops-and-joyous-journe-e34bc83a6f\\image-1.jpg" },
            { type = "p", text = "Flex your muscle and push back against the Void in the Midnight 12.0.5 content update, Joyous Journeys are alive and well in Mists of Pandaria Classic, and get your Cuddly Pearl Grrgle Housing decor item when you catch participating Twitch streams. Each week meets you with adventurous discovery and fresh rewards—be sure to check in to learn more about what awaits you in Azeroth." },
